    {
      "id": "home-page",
      "surfaceId": "home",
      "pageId": "home-page",
      "name": "首页",
      "route": "pages/Home",
      "tabId": "tab-home",
      "semanticTargets": [
        {
          "id": "home-today-status-card",
          "role": "assertion",
          "binding": "/today/status"
