        {
          "id": "home-spin-wheel-button",
          "role": "action",
          "event": "navigate-to-wheel"
        },
        {
          "id": "home-ingredient-button",
          "role": "action",
          "event": "navigate-to-ingredient"
        },
        {
          "id": "home-filter-button",
          "role": "action",
          "event": "navigate-to-filter"
        },
        {
          "id": "home-checkin-button",
          "role": "action",
          "event": "navigate-to-checkin"
        },
        {
          "id": "home-recent-checkin-list",
          "role": "list",
          "binding": "/checkins/recent",
          "itemIdPattern": "home-checkin-{id}",
          "emptyStateId": "home-empty-checkin"
        }
      ]
    },
    {
      "id": "recommend-page",
      "surfaceId": "recommend",
