          "event": "switch-to-ingredient"
        },
        {
          "id": "recommend-segment-filter",
          "role": "action",
          "event": "switch-to-filter"
        }
      ]
    },
    {
      "id": "wheel-page",
      "surfaceId": "wheel",
      "pageId": "wheel-page",
      "name": "转盘抽菜",
      "route": "pages/Wheel",
      "parentTabId": "tab-recommend",
      "semanticTargets": [
        {
          "id": "wheel-spin-button",
          "role": "action",
          "event": "spin-wheel"
        },
        {
          "id": "wheel-canvas",
          "role": "assertion",
          "binding": "/wheel/state"
        },
        {
          "id": "wheel-result-panel",
          "role": "assertion",
