          "id": "wheel-add-candidate-input",
          "role": "input",
          "event": "add-wheel-candidate"
        },
        {
          "id": "wheel-add-candidate-button",
          "role": "action",
          "event": "add-wheel-candidate"
        },
        {
          "id": "wheel-clear-candidates-button",
          "role": "action",
          "event": "clear-wheel-candidates"
        },
        {
          "id": "wheel-go-checkin-button",
          "role": "action",
          "event": "navigate-to-checkin-with-result"
        }
      ]
    },
