      "id": "ingredient-page",
      "surfaceId": "ingredient",
      "pageId": "ingredient-page",
      "name": "食材推荐",
      "route": "pages/Ingredient",
      "parentTabId": "tab-recommend",
      "semanticTargets": [
        {
          "id": "ingredient-input",
          "role": "input",
          "event": "add-ingredient"
