        {
          "id": "ingredient-add-button",
          "role": "action",
          "event": "add-ingredient"
        },
        {
          "id": "ingredient-tag-list",
          "role": "list",
          "binding": "/ingredients",
          "itemIdPattern": "ingredient-tag-{id}",
          "emptyStateId": "ingredient-empty"
        },
        {
          "id": "ingredient-recommend-button",
          "role": "action",
          "event": "recommend-by-ingredients"
        },
        {
          "id": "ingredient-result-list",
          "role": "list",
          "binding": "/recommendations/ingredient",
          "itemIdPattern": "ingredient-result-{id}",
          "emptyStateId": "ingredient-result-empty"
        },
        {
          "id": "ingredient-clear-button",
          "role": "action",
          "event": "clear-ingredients"
        }
      ]
    },
