        {
          "id": "filter-mood-list",
          "role": "list",
          "binding": "/filters/mood",
          "itemIdPattern": "filter-mood-{id}"
        },
        {
          "id": "filter-time-list",
          "role": "list",
          "binding": "/filters/time",
          "itemIdPattern": "filter-time-{id}"
        },
