          "id": "filter-apply-button",
          "role": "action",
          "event": "apply-filter"
        },
        {
          "id": "filter-result-list",
          "role": "list",
          "binding": "/recommendations/filter",
          "itemIdPattern": "filter-result-{id}",
          "emptyStateId": "filter-result-empty"
