        {
          "id": "checkin-meal-lunch",
          "role": "action",
          "event": "select-meal-type",
          "eventContext": { "meal": "lunch" }
        },
        {
          "id": "checkin-meal-dinner",
          "role": "action",
          "event": "select-meal-type",
          "eventContext": { "meal": "dinner" }
        },
