          "role": "input",
          "event": "update-checkin-dish"
        },
        {
          "id": "checkin-note-input",
          "role": "input",
          "event": "update-checkin-note"
        },
        {
          "id": "checkin-save-button",
          "role": "action",
          "event": "save-checkin"
        },
        {
          "id": "checkin-share-button",
          "role": "action",
          "event": "navigate-to-share"
        },
        {
          "id": "checkin-history-list",
          "role": "list",
          "binding": "/checkin/history",
          "itemIdPattern": "checkin-history-{id}",
          "emptyStateId": "checkin-history-empty"
        }
      ]
    },
    {
      "id": "share-page",
