          "id": "share-card-preview",
          "role": "assertion",
          "binding": "/share/card"
        },
        {
          "id": "share-save-button",
          "role": "action",
          "event": "save-share-card"
        },
        {
          "id": "share-system-button",
          "role": "action",
          "event": "system-share-card"
        },
        {
          "id": "share-template-list",
          "role": "list",
          "binding": "/share/templates",
          "itemIdPattern": "share-template-{id}"
        },
        {
          "id": "share-caption-input",
          "role": "input",
          "event": "update-share-caption"
        }
      ]
    },
    {
      "id": "profile-page",
      "surfaceId": "profile",
      "pageId": "profile-page",
      "name": "我的",
      "route": "pages/Profile",
      "tabId": "tab-profile",
      "semanticTargets": [
        {
          "id": "profile-dish-library-button",
          "role": "action",
          "event": "navigate-to-dish-library"
        },
        {
          "id": "profile-settings-button",
          "role": "action",
          "event": "open-settings"
        }
      ]
    },
    {
      "id": "dish-page",
      "surfaceId": "dish",
      "pageId": "dish-page",
      "name": "菜品管理",
      "route": "pages/DishLibrary",
      "semanticTargets": [
        {
          "id": "dish-add-button",
          "role": "action",
          "event": "open-dish-form"
        },
        {
          "id": "dish-list",
          "role": "list",
          "binding": "/dishes",
          "itemIdPattern": "dish-item-{id}",
          "emptyStateId": "dish-empty"
