          "id": "dish-form-save-button",
          "role": "action",
          "event": "save-dish"
        },
        {
          "id": "dish-form-delete-button",
          "role": "action",
          "event": "delete-dish"
        }
      ]
    }
  ],
  "events": [
    { "name": "navigate-to-wheel", "description": "跳转到转盘页" },
    { "name": "navigate-to-ingredient", "description": "跳转到食材推荐页" },
    { "name": "navigate-to-filter", "description": "跳转到筛选页" },
    { "name": "navigate-to-checkin", "description": "跳转到打卡页" },
    { "name": "navigate-to-checkin-with-result", "description": "携带转盘结果跳转到打卡页" },
    { "name": "navigate-to-share", "description": "跳转到分享页" },
    { "name": "navigate-to-dish-library", "description": "跳转到菜品管理页" },
    { "name": "switch-to-wheel", "description": "推荐页切换到转盘面板" },
    { "name": "switch-to-ingredient", "description": "推荐页切换到食材面板" },
    { "name": "switch-to-filter", "description": "推荐页切换到筛选面板" },
    { "name": "spin-wheel", "description": "开始转盘抽取" },
    { "name": "add-wheel-candidate", "description": "添加转盘候选菜品" },
    { "name": "clear-wheel-candidates", "description": "清空转盘候选" },
    { "name": "add-ingredient", "description": "添加冰箱食材" },
    { "name": "recommend-by-ingredients", "description": "基于食材推荐菜品" },
    { "name": "clear-ingredients", "description": "清空已添加食材" },
    { "name": "apply-filter", "description": "应用心情/时段筛选" },
    { "name": "reset-filter", "description": "重置筛选条件" },
    { "name": "select-meal-type", "description": "选择打卡餐别" },
    { "name": "update-checkin-dish", "description": "更新打卡菜品" },
    { "name": "update-checkin-note", "description": "更新打卡备注" },
    { "name": "save-checkin", "description": "保存打卡记录" },
    { "name": "update-share-caption", "description": "更新分享卡片文案" },
    { "name": "save-share-card", "description": "保存分享卡片到相册" },
    { "name": "system-share-card", "description": "调用系统分享卡片" },
    { "name": "open-dish-form", "description": "打开菜品添加/编辑表单" },
    { "name": "search-dishes", "description": "搜索菜品" },
    { "name": "update-dish-name", "description": "更新菜品名称" },
    { "name": "update-dish-tags", "description": "更新菜品标签" },
    { "name": "save-dish", "description": "保存菜品" },
    { "name": "delete-dish", "description": "删除菜品" },
    { "name": "open-settings", "description": "打开设置" }
  ],
  "bindings": [
    { "path": "/today/status", "type": "object", "description": "今日打卡状态" },
    { "path": "/wheel/state", "type": "enum", "description": "转盘状态 idle/spinning/finished" },
    { "path": "/wheel/result", "type": "object", "description": "转盘抽中结果" },
    { "path": "/wheel/candidates", "type": "array", "description": "转盘候选菜品列表" },
    { "path": "/ingredients", "type": "array", "description": "冰箱食材列表" },
    { "path": "/recommendations/ingredient", "type": "array", "description": "基于食材的推荐结果" },
    { "path": "/filters/mood", "type": "array", "description": "心情筛选项" },
    { "path": "/filters/time", "type": "array", "description": "时段筛选项" },
    { "path": "/recommendations/filter", "type": "array", "description": "筛选后的菜品结果" },
    { "path": "/checkin/calendar", "type": "array", "description": "打卡日历数据" },
    { "path": "/checkin/streak", "type": "number", "description": "连续打卡天数" },
    { "path": "/checkin/total", "type": "number", "description": "累计打卡天数" },
    { "path": "/checkin/history", "type": "array", "description": "打卡历史列表" },
    { "path": "/share/card", "type": "object", "description": "分享卡片数据" },
    { "path": "/share/templates", "type": "array", "description": "分享卡片模板" },
    { "path": "/dishes", "type": "array", "description": "用户菜品库" }
  ],
  "testTargets": [
    { "id": "home-spin-wheel-button", "action": "click", "expect": "navigate-to-wheel" },
    { "id": "wheel-spin-button", "action": "click", "expect": "wheel-result-panel visible" },
    { "id": "ingredient-recommend-button", "action": "click", "expect": "ingredient-result-list populated" },
    { "id": "filter-apply-button", "action": "click", "expect": "filter-result-list populated" },
    { "id": "checkin-save-button", "action": "click", "expect": "checkin-history-list updated" },
    { "id": "share-save-button", "action": "click", "expect": "save-share-card event" },
    { "id": "dish-form-save-button", "action": "click", "expect": "dish-list updated" }
  ]
}

